const cvProfile = $input.first().json.output;
const prefs = $('Normalize Input').first().json;

const urlMap = {
  'Backend':  'https://dev.bg/company/jobs/back-end-development/',
  'Frontend': 'https://dev.bg/company/jobs/front-end-development/',
  'Fullstack': 'https://dev.bg/company/jobs/full-stack-development/',
  'QA':       'https://dev.bg/company/jobs/quality-assurance/',
  'Mobile':   'https://dev.bg/company/jobs/mobile/',
  'DevOps':   'https://dev.bg/company/jobs/infrastructure/',
  'Data':     'https://dev.bg/company/jobs/data-science-and-analytics/'
};

const categoryMap = {
  'Backend':  ['Backend', 'Fullstack'],
  'Frontend': ['Frontend', 'Fullstack'],
  'Fullstack': ['Backend', 'Frontend', 'Fullstack'],
  'QA':       ['QA'],
  'Mobile':   ['Mobile'],
  'DevOps':   ['DevOps'],
  'Data':     ['Data']
};

const locationMap = {
  'Remote':       'remote',
  'София':        'sofiya',
  'Пловдив':      'plovdiv',
  'Варна':        'varna',
  'Бургас':       'burgas',
  'Русе':         'ruse',
  'Стара Загора': 'stara-zagora'
};

// The extractor's job_type SHOULD be one of our canonical categories, but the LLM sometimes
// free-forms it (e.g. "Full-Stack Web Developer" instead of "Fullstack"). Normalize to a known
// category so we never build an "undefined" scrape URL (which silently returns zero jobs).
function normalizeJobType(raw){
  const t = String(raw || '').toLowerCase();
  if (/full[\s-]?stack/.test(t)) return 'Fullstack';
  if (/front[\s-]?end/.test(t)) return 'Frontend';
  if (/back[\s-]?end/.test(t)) return 'Backend';
  if (/\bqa\b|quality|tester|testing/.test(t)) return 'QA';
  if (/mobile|android|\bios\b|flutter|react native/.test(t)) return 'Mobile';
  if (/devops|\bsre\b|infrastructure|platform eng/.test(t)) return 'DevOps';
  if (/data (scien|eng|analy)|analytic|machine learning|\bml\b/.test(t)) return 'Data';
  const known = ['Backend','Frontend','Fullstack','QA','Mobile','DevOps','Data'];
  return known.find(k => k.toLowerCase() === t) || 'Backend';
}
const jobType = normalizeJobType(cvProfile?.job_type);
const categories = categoryMap[jobType] || [jobType];
const locationSlug = locationMap[prefs.location];

const cvProfileData = {
  skills:                cvProfile?.skills || [],
  programming_languages: cvProfile?.programming_languages || [],
  primary_languages:     cvProfile?.primary_languages || [],
  primary_stack:         cvProfile?.primary_stack || [],
  frameworks:            cvProfile?.frameworks || [],
  tools:                 cvProfile?.tools || [],
  spoken_languages:      cvProfile?.spoken_languages || [],
  experience_level:      cvProfile?.experience_level || 'Mid',
  job_type:              jobType,
  years_of_experience:   cvProfile?.years_of_experience || 0,
  job_titles:            cvProfile?.job_titles || []
};

// One page-1 URL per category. Pagination (fetching the remaining pages) is handled in
// "Parse & Merge Categories", which reads the real page count from each page-1 HTML.
return categories.map(cat => {
  const baseUrl = urlMap[cat];
  const scrapeUrl = locationSlug
    ? baseUrl + '?_job_location=' + encodeURIComponent(locationSlug)
    : baseUrl;
  return {
    json: {
      cv_profile:  cvProfileData,
      scrape_url:  scrapeUrl,
      category:    cat,
      location:    prefs.location,
      language:    prefs.language,
      user_email:  prefs.user_email,
      days_back:   prefs.days_back || 5
    }
  };
});

const item = $input.first();
const binaryData = item.binary || {};
const binaryKeys = Object.keys(binaryData);

if (binaryKeys.length === 0) {
  return [{ json: { ...item.json, cv_valid: false, error_code: 'NO_FILE', error_message: 'Моля качете CV файл в PDF формат.' } }];
}

const pdfField = binaryKeys.find(k => {
  const b = binaryData[k];
  return b.fileType === 'pdf' || (b.mimeType && b.mimeType.toLowerCase().includes('pdf'));
});

if (!pdfField) {
  const got = binaryData[binaryKeys[0]];
  const gotType = got.fileExtension || got.mimeType || 'неизвестен';
  return [{
    json: { ...item.json, cv_valid: false, error_code: 'WRONG_FORMAT', error_message: `Само PDF файлове се поддържат. Файлът е в ${gotType} формат — моля конвертирайте до PDF.` },
    binary: binaryData
  }];
}

return [{
  json: { ...item.json, cv_valid: true, binary_field: pdfField },
  binary: binaryData
}];

const item = $input.first();
const jobs = (item.json.output?.jobs || []);
const daysBack = $('Build dev.bg Target URL').first().json.days_back || 5;
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - daysBack);

const jobsFiltered = jobs.filter(job => {
  if (!job.date_posted) return true;
  return new Date(job.date_posted) >= cutoff;
});

return [{ json: { output: { jobs: jobsFiltered } } }];

const item = $input.first();
const jobs = (item.json.jobs || []).slice(0, 40);
const cv = $('Build dev.bg Target URL').first().json.cv_profile;

const cvSection = '=== CV PROFILE ===\n' +
  'Skills: ' + cv.skills.join(', ') + '\n' +
  'Programming Languages: ' + cv.programming_languages.join(', ') + '\n' +
  'Frameworks: ' + cv.frameworks.join(', ') + '\n' +
  'Tools: ' + cv.tools.join(', ') + '\n' +
  'Spoken Languages: ' + cv.spoken_languages.join(', ') + '\n' +
  'Experience Level: ' + cv.experience_level + '\n' +
  'Years of Experience: ' + cv.years_of_experience + '\n' +
  'Previous Roles: ' + cv.job_titles.join(', ');

const jobsSection = jobs.map((job, i) =>
  '--- JOB ' + (i + 1) + ' ---\n' +
  'Title: ' + job.title + '\n' +
  'Company: ' + job.company + '\n' +
  'Location: ' + job.location + '\n' +
  'Type: ' + job.employment_type + '\n' +
  'Description: ' + (job.full_description || job.description || 'N/A')
).join('\n\n');

const scoring_text = cvSection + '\n\n=== JOB LISTINGS (' + jobs.length + ' total) ===\n\n' + jobsSection + '\n\nReturn a JSON results array with exactly ' + jobs.length + ' entries, one per job in order.';

const jobs_text = '=== JOB LISTINGS (' + jobs.length + ' total) ===\n\n' + jobs.map((job, i) =>
  '--- JOB ' + (i + 1) + ' ---\n' +
  'Title: ' + job.title + '\n' +
  'Company: ' + job.company + '\n' +
  'Description: ' + (job.full_description || job.description || 'N/A')
).join('\n\n') + '\n\nReturn a JSON requirements array with exactly ' + jobs.length + ' entries, one per job in order.';

return [{ json: { scoring_text, jobs, jobs_text, cv_profile: cv } }];

const summaries = (($input.first().json.output) || {}).summaries || [];
const scored = $('Build Scoring Input').first().json.scored || [];
const jobs = $('Prepare Batch Input').first().json.jobs || [];
const cv = $('Prepare Batch Input').first().json.cv_profile || {};
const requirements = (($('Extract Job Requirements').first().json.output) || {}).requirements || [];

function levelRank(s){
  const t = ' ' + (s||'').toLowerCase() + ' ';
  if (t.includes('lead')||t.includes('principal')||t.includes('staff')||t.includes('chief')||t.includes('architect')||t.includes('head of')) return 4;
  if (t.includes('senior')||t.includes('sr.')||t.includes('sr ')) return 3;
  if (t.includes('middle')||t.includes('mid-')||t.includes('mid ')||t.includes('intermediate')||t.includes('regular')) return 2;
  if (t.includes('junior')||t.includes('jr.')||t.includes('jr ')||t.includes('entry')||t.includes('graduate')||t.includes('trainee')||t.includes('intern')) return 1;
  return 0;
}
const candidateRank = levelRank(cv.experience_level);

const sumByIndex = {};
for (const s of summaries){ if (s && s.job_index != null) sumByIndex[s.job_index] = s.summary; }
const scoredByIndex = {};
for (const s of scored){ scoredByIndex[s.job_index] = s; }

const out = [];
jobs.forEach((job, i) => {
  const idx = i + 1;
  const sc = scoredByIndex[idx] || {};
  const req = requirements[i] || {};

  const jobRank = Math.max(levelRank(req.experience_level), levelRank(job.title));
  const overqualified = candidateRank > 0 && jobRank > 0 && (candidateRank - jobRank >= 2);
  if (overqualified) return;

  const matched = Array.isArray(sc.matched_skills) ? sc.matched_skills : [];
  const missing = Array.isArray(sc.missing_skills) ? sc.missing_skills : [];
  let summary = sumByIndex[idx];
  if (!summary || !String(summary).trim()) {
    summary = matched.length
      ? 'Съвпадение по: ' + matched.slice(0,3).join(', ') + '.'
      : 'Слабо съвпадение с изискванията.';
  }

  out.push({ json: {
    title:            job.title || '',
    company:          job.company || '',
    url:              job.url || '',
    date_posted:      job.date_posted || '',
    location:         job.location || '',
    employment_type:  job.employment_type || '',
    description:      (job.description || '').substring(0, 500),
    score:            typeof sc.score === 'number' ? sc.score : 0,
    matched_skills:   matched,
    missing_skills:   missing,
    experience_match: sc.experience_match === true,
    main_stack:       Array.isArray(sc.main_stack) ? sc.main_stack : [],
    main_alt:         sc.main_alt || '',
    summary:          summary,
    source:           job.source || 'dev.bg'
  }});
});

return out;

const httpItems = $input.all();
const splitItems = $('Split Jobs for Fetch').all();

return httpItems.map((item, i) => {
  const markdown = (item.json.data && item.json.data.markdown || '').substring(0, 4000);
  const originalJob = (splitItems[i] && splitItems[i].json) || {};

  return { json: {
    title: originalJob.title || '',
    company: originalJob.company || '',
    url: originalJob.url || '',
    date_posted: originalJob.date_posted || '',
    location: originalJob.location || '',
    employment_type: originalJob.employment_type || '',
    description: originalJob.description || '',
    full_description: markdown || originalJob.description || ''
  }};
});

// Parses dev.bg listing pages into job objects AND paginates: for each category's page 1
// (received as input) it reads the real last-page number from the FacetWP pager embedded in
// the HTML, then fetches the remaining pages itself. Count-driven — no wasted requests.
// Pagination is wrapped in try/catch so a failed page (or an environment without
// this.helpers.httpRequest) degrades gracefully to whatever pages we already have.
const allItems = $input.all();
const builtUrls = $('Build dev.bg Target URL').all();
const allJobs = [];
const seenUrls = new Set();
const UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36';
const MAX_PAGES = 10;

function decodeHtmlEntities(str) {
  return str
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#039;/g, "'")
    .replace(/&nbsp;/g, ' ')
    .replace(/&#(\d+);/g, (_, code) => String.fromCharCode(parseInt(code)))
    .replace(/&#x([0-9a-fA-F]+);/g, (_, hex) => String.fromCharCode(parseInt(hex, 16)));
}

function convertBgDate(dateStr) {
  const months = { 'яну': 1, 'фев': 2, 'мар': 3, 'апр': 4, 'май': 5, 'юни': 6, 'юли': 7, 'авг': 8, 'сеп': 9, 'окт': 10, 'ное': 11, 'дек': 12 };
  const match = dateStr.match(/(\d+)\s+(\S+)/);
  if (!match) return new Date().toISOString().split('T')[0];
  const day = parseInt(match[1]);
  const monthKey = match[2].toLowerCase().substring(0, 3);
  const month = months[monthKey] || (new Date().getMonth() + 1);
  const year = new Date().getFullYear();
  return `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
}

function parseJobsFromHtml(html) {
  const jobs = [];
  const blocks = html.split('<div class="job-list-item');
  blocks.shift();
  for (const block of blocks) {
    const urlMatch = block.match(/href="(https:\/\/dev\.bg\/company\/jobads\/[^"]+)"/);
    if (!urlMatch) continue;
    const url = urlMatch[1];
    const titleMatch = block.match(/class="job-title[^"]*"[^>]*>\s*([^<]+?)\s*<\/h6>/);
    const title = titleMatch ? decodeHtmlEntities(titleMatch[1].trim()) : '';
    if (!title) continue;
    const companyMatch = block.match(/class="company-name[^"]*"[^>]*>\s*([^<]+?)\s*<\/span>/);
    const company = companyMatch ? decodeHtmlEntities(companyMatch[1].trim()) : '';
    const dateMatch = block.match(/class="date[^"]*"[^>]*>\s*([^<]+?)\s*<\/span>/);
    const dateRaw = dateMatch ? dateMatch[1].trim() : '';
    const date_posted = convertBgDate(dateRaw);
    const isRemote = /class="badge[^"]*remote[^"]*"/.test(block);
    const isHybrid = /class="badge[^"]*hybrid[^"]*"/.test(block);
    let location = 'Bulgaria';
    if (isRemote) location = 'Remote';
    else if (isHybrid) location = 'Hybrid';
    const techMatches = [...block.matchAll(/<img[^>]+title="([^"]+)"[^>]*>/g)];
    const techStack = [...new Set(techMatches.map(m => m[1]).filter(t => t && !t.toLowerCase().includes('icon') && t.length > 1))];
    jobs.push({
      title, company, url, date_posted, location,
      employment_type: 'Full-time',
      description: techStack.length > 0 ? 'Tech stack: ' + techStack.join(', ') : '',
      source: 'dev.bg'
    });
  }
  return jobs;
}

function lastPageOf(html) {
  const clean = String(html).replace(/\\"/g, '"');
  let max = 1;
  const re = /data-page="(\d+)"/g;
  let m;
  while ((m = re.exec(clean)) !== null) { const n = parseInt(m[1], 10); if (n > max) max = n; }
  return max;
}

function addJobs(html) {
  for (const job of parseJobsFromHtml(html)) {
    if (!seenUrls.has(job.url)) { seenUrls.add(job.url); allJobs.push(job); }
  }
}

for (let i = 0; i < allItems.length; i++) {
  const html = allItems[i].json.data || '';
  if (!html) continue;
  addJobs(html);

  const baseUrl = (builtUrls[i] && builtUrls[i].json && builtUrls[i].json.scrape_url) || '';
  if (!baseUrl) continue;

  const lastPage = Math.min(lastPageOf(html), MAX_PAGES);
  for (let p = 2; p <= lastPage; p++) {
    const pageUrl = baseUrl + (baseUrl.includes('?') ? '&' : '?') + '_paged=' + p;
    try {
      const resp = await this.helpers.httpRequest({ url: pageUrl, method: 'GET', headers: { 'User-Agent': UA }, json: false, timeout: 20000 });
      const pageHtml = typeof resp === 'string' ? resp : ((resp && resp.body) || '');
      if (pageHtml) addJobs(pageHtml);
    } catch (e) {
      // transient page error or no http helper — keep what we have and move on
    }
  }
}

return [{ json: { output: { jobs: allJobs } } }];

// Relevance pre-filter: rank every in-period listing by how its tech-tag set ("icons") overlaps
// the candidate's stack, then keep the best matches for the expensive AI analysis. Ranking is
// TWO-LEVEL: first by the number of MAIN matches (the candidate's defining stack — primary_stack:
// the 3-5 languages/frameworks/tools they actually build with), then by SECONDARY matches
// (everything else they know, incl. markup/styling and tools) as a tie-breaker, then by date.
// A job needs at least ONE MAIN match to be evaluated at all — sharing only HTML/CSS or a tool
// (e.g. Git, MySQL) is NOT enough. We DON'T pad to 15 with near-irrelevant listings; if the MAIN
// matches are thin we top up to a small floor with the best secondary-only jobs, no further.
// Role-agnostic — a dev matches on languages/frameworks, a QA on its testing frameworks/tools.
const item = $input.first();
const jobs = item.json.output?.jobs || [];
const cv = $('Build dev.bg Target URL').first().json.cv_profile || {};

const ALIASES = {'js':'javascript','ts':'typescript','postgres':'postgresql','node':'node.js','nodejs':'node.js','k8s':'kubernetes','golang':'go','reactjs':'react','react.js':'react','nextjs':'next.js','vuejs':'vue.js','vue':'vue.js','css3':'css','html5':'html','dotnet':'.net','.net core':'.net','spring framework':'spring','springboot':'spring boot','tailwind css':'tailwindcss','tailwind':'tailwindcss','scss/sass':'scss'};
const norm = s => { const t = (s || '').toLowerCase().trim(); return ALIASES[t] || t; };

// Markup / styling / ubiquitous UI tech — never counts as MAIN, only as a secondary tie-breaker.
// (A candidate's real coding direction is defined by languages/frameworks, not by HTML/CSS.)
const MARKUP = new Set(['html', 'css', 'scss', 'sass', 'less', 'tailwindcss', 'bootstrap', 'jquery'].map(norm));

// MAIN = the candidate's defining stack (LLM-picked primary_stack), minus any markup that slipped in.
// Fallback for older/cached profiles without primary_stack: professionally-used languages + frameworks.
let mainList = (cv.primary_stack || []).map(norm).filter(Boolean).filter(t => !MARKUP.has(t));
if (mainList.length === 0) {
  mainList = [...(cv.primary_languages || []), ...(cv.frameworks || [])].map(norm).filter(Boolean).filter(t => !MARKUP.has(t));
}
const mainSet = new Set(mainList);

// SECONDARY = everything else the candidate has (other languages/frameworks, tools, skills, and the
// demoted markup). Used ONLY as a tie-breaker between jobs that already share a MAIN tech.
const secondarySet = new Set([
  ...(cv.programming_languages || []),
  ...(cv.frameworks || []),
  ...(cv.tools || []),
  ...(cv.skills || [])
].map(norm).filter(Boolean).filter(t => !mainSet.has(t)));

// Non-discriminating tags: present on almost every listing, so they don't indicate fit.
const IGNORE = new Set([
  'git', 'github', 'gitlab', 'bitbucket', 'svn',
  'agile', 'scrum', 'kanban', 'jira', 'confluence',
  'english', 'bulgarian', 'german', 'french', 'spanish', 'russian', 'italian',
  'dutch', 'portuguese', 'polish', 'romanian', 'greek', 'turkish', 'ukrainian'
].map(norm));

function tagsOf(job) {
  if (Array.isArray(job.tech_tags) && job.tech_tags.length) return job.tech_tags;
  return String(job.description || '').replace('Tech stack:', '').split(',');
}
// Count DISTINCT shared technologies, split by tier: MAIN (defining stack) and SECONDARY (the rest).
function tiers(job) {
  let main = 0, sec = 0;
  const seen = new Set();
  for (const raw of tagsOf(job)) {
    const t = norm(String(raw).trim());
    if (!t || seen.has(t) || IGNORE.has(t)) continue;
    seen.add(t);
    if (mainSet.has(t)) main++;
    else if (secondarySet.has(t)) sec++;
  }
  return { main, sec };
}

const MAX_JOBS = 15;   // hard ceiling sent to the scorer
const MIN_JOBS = 6;    // if MAIN matches are thinner than this, top up with secondary-only up to here

// Two-level ranking: more MAIN matches always wins; SECONDARY breaks ties; then original order (date).
// So a job sharing 2 of the candidate's defining techs always ranks above one sharing only 1.
const ranked = jobs
  .map((job, i) => { const t = tiers(job); return { job, i, main: t.main, sec: t.sec }; })
  .sort((a, b) => b.main - a.main || b.sec - a.sec || a.i - b.i);

// Primary pool: jobs sharing >=1 MAIN tech — the real matches. Take up to MAX_JOBS.
let keptR = ranked.filter(r => r.main > 0).slice(0, MAX_JOBS);

// If MAIN matches are too thin, top up ONLY up to MIN_JOBS (never to MAX_JOBS) with the best
// secondary-only jobs — so we never pad the full list with near-irrelevant listings.
if (keptR.length < MIN_JOBS) {
  const secOnly = ranked.filter(r => r.main === 0 && r.sec > 0);
  keptR = keptR.concat(secOnly.slice(0, MIN_JOBS - keptR.length));
}

let kept = keptR.map(r => r.job);
// Safety net: sparse/odd tagging left nothing overlapping → never return empty, keep most-recent.
if (kept.length === 0) kept = jobs.slice(0, MAX_JOBS);

return [{ json: { output: { jobs: kept } } }];

const jobs = $('Prepare Batch Input').first().json.jobs || [];
const cv = $('Prepare Batch Input').first().json.cv_profile;
const requirements = $input.first().json.output.requirements || [];

const cvAllTech = [...(cv.skills||[]), ...(cv.programming_languages||[]), ...(cv.frameworks||[]), ...(cv.tools||[])];
const cvAllTechLower = cvAllTech.map(s => s.toLowerCase().trim());
const hasTech = (n) => cvAllTechLower.some(t => t.includes(n));

const years = cv.years_of_experience || 0;
const level = (cv.experience_level || '').toLowerCase();
const jobType = (cv.job_type || '').toLowerCase();
const isMidPlus = ['mid','senior','lead'].includes(level) || years >= 3;
const hasAnyDb = ['postgresql','postgres','mysql','mariadb','oracle','sql server','mssql','sqlite','rds'].some(db => hasTech(db));

const IMPLIED = [
  { s: 'Git',    w: () => isMidPlus },
  { s: 'GitHub', w: () => isMidPlus },
  { s: 'Maven',  w: () => hasTech('spring') },
  { s: 'SQL',    w: () => ['backend','fullstack','full-stack','data'].includes(jobType) || hasAnyDb }
];
const impliedSkills = [];
for (const r of IMPLIED) { if (r.w() && !cvAllTechLower.includes(r.s.toLowerCase())) impliedSkills.push(r.s); }

const LINEAGE = [
  { w: () => hasTech('typescript') || hasTech('node'), a: 'JavaScript', src: () => hasTech('typescript') ? 'TypeScript' : 'Node.js' },
  { w: () => hasTech('scss') || hasTech('sass'),       a: 'CSS',        src: () => hasTech('scss') ? 'SCSS' : 'SASS' },
  { w: () => hasTech('spring'),                        a: 'Spring',     src: () => 'Spring' }
];
const lineageSkills = [];
const derivedFrom = {};
for (const r of LINEAGE) { const al = r.a.toLowerCase(); if (r.w() && !cvAllTechLower.includes(al) && !lineageSkills.map(x=>x.toLowerCase()).includes(al)) { lineageSkills.push(r.a); derivedFrom[al] = r.src(); } }

const candidateSkills = [...cvAllTech, ...impliedSkills, ...lineageSkills];

const AWS_SERVICES = ['ec2','rds','s3','lambda','ecs','eks','dynamodb','cloudwatch','codedeploy','cloudformation','sqs','sns','cloudfront','elasticache','redshift','kinesis','fargate','opensearch'];
const CLOUD = [
  { term: 'AWS',   prov: 'aws',   svc: AWS_SERVICES },
  { term: 'Azure', prov: 'azure', svc: [] },
  { term: 'GCP',   prov: 'gcp',   svc: ['google cloud','bigquery','gke'] }
];
for (const c of CLOUD) {
  if (cvAllTechLower.includes(c.term.toLowerCase())) continue;
  const has = candidateSkills.some(s => {
    const sl = s.toLowerCase().trim();
    return sl === c.prov || sl.includes(c.prov) || c.svc.includes(sl);
  });
  if (has) candidateSkills.push(c.term);
}

const spokenLangs = cv.spoken_languages || [];

const ALIASES = {'js':'javascript','ecmascript':'javascript','ts':'typescript','postgres':'postgresql','postgre':'postgresql','node':'node.js','nodejs':'node.js','k8s':'kubernetes','csharp':'c#','golang':'go','reactjs':'react','react.js':'react','nextjs':'next.js','vuejs':'vue.js','vue':'vue.js','css3':'css','html5':'html','dotnet':'.net','.net core':'.net','.net 8':'.net','.net framework':'.net','rest':'rest apis','rest api':'rest apis','restful apis':'rest apis','restful api':'rest apis','tailwind css':'tailwindcss','tailwind':'tailwindcss'};
function norm(s){ const t = (s||'').toLowerCase().trim(); return ALIASES[t] || t; }
const candidateNorm = candidateSkills.map(norm);
const candidateSet = new Set(candidateNorm);
function langCovered(jobLang){ const jl = norm(jobLang); return spokenLangs.some(sl => norm(sl).includes(jl)); }

const primarySet = new Set((cv.primary_languages || []).map(norm));
const SECONDARY_LANG_CREDIT = 0.4;

function skillBase(s){ return norm(String(s).split(' (')[0]); }
function dedupSkills(arr){
  const byBase = new Map();
  for (const s of arr){
    const str = String(s);
    const annotated = str.includes(' (');
    const base = skillBase(str);
    if (!byBase.has(base)) { byBase.set(base, s); }
    else { const ex = String(byBase.get(base)); if (ex.includes(' (') && !annotated) byBase.set(base, s); }
  }
  return [...byBase.values()];
}

const FOUNDATIONAL = new Set(['git','github','gitlab','bitbucket','agile','scrum','kanban','jira','confluence'].map(norm));
const HUMAN_LANGS = new Set(['english','bulgarian','german','french','spanish','russian','italian','dutch','portuguese','polish','romanian','greek','turkish','ukrainian','czech','hungarian','croatian','serbian','arabic','chinese','japanese'].map(norm));
const LANGUAGES = new Set(['java','kotlin','go','python','c#','javascript','typescript','php','ruby','c++','c','rust','scala','swift','objective-c','perl','dart','elixir','clojure','groovy','f#','vb.net','lua','haskell','julia'].map(norm));
const FRONTEND_FRAMEWORKS = new Set(['react','angular','angularjs','vue.js','svelte','next.js','nuxt'].map(norm));
const isFrontendCandidate = ['frontend','fullstack','full-stack'].includes(jobType);
const techWeight = (t) => {
  const n = norm(t);
  if (LANGUAGES.has(n)) return 3;
  if (isFrontendCandidate && FRONTEND_FRAMEWORKS.has(n)) return 2;
  return 1;
};

const MAIN_DISPLAY = {'java':'Java','kotlin':'Kotlin','go':'Go','python':'Python','c#':'C#','javascript':'JavaScript','typescript':'TypeScript','php':'PHP','ruby':'Ruby','c++':'C++','rust':'Rust','scala':'Scala','swift':'Swift','.net':'.NET','node.js':'Node.js','react':'React','angular':'Angular','vue.js':'Vue.js','spring':'Spring','django':'Django','laravel':'Laravel','blazor':'Blazor','dart':'Dart','elixir':'Elixir'};
const MAIN_KNOWN = new Set(Object.keys(MAIN_DISPLAY));
const MAIN_LANG_SET = new Set(['java','kotlin','go','python','c#','javascript','typescript','php','ruby','c++','rust','scala','swift','.net','dart','elixir']);
const FRONTEND_FW = new Set(['react','angular','vue.js','svelte'].map(norm));
const BACKEND_MS = new Set(['java','kotlin','go','python','c#','php','ruby','rust','scala','.net','node.js','elixir','c++'].map(norm));
function detectMainStack(title, description){
  const titleTokens = []; const tseen = new Set();
  for (const tok of String(title || '').toLowerCase().split(/[^a-z0-9+#.]+/).filter(Boolean)){
    const n = norm(tok); if (MAIN_KNOWN.has(n) && !tseen.has(n)){ tseen.add(n); titleTokens.push(n); }
  }
  const tLower = String(title || '').toLowerCase();
  const roleFull  = /full[ \-]?stack/.test(tLower);
  const roleFront = /front[ \-]?end/.test(tLower);
  const roleBack  = /back[ \-]?end/.test(tLower);
  const iconTags = String(description || '').replace('Tech stack:', '').split(',').map(s => norm(s.trim())).filter(Boolean);
  const pick = (set) => {
    const fromTitle = titleTokens.find(t => set.has(t));
    if (fromTitle) return fromTitle;
    const inIcons = iconTags.filter(t => set.has(t));
    return inIcons.length === 1 ? inIcons[0] : null;
  };
  const backend = pick(BACKEND_MS);
  const frontend = pick(FRONTEND_FW);
  let out;
  if (roleFront)               out = [frontend || backend];
  else if (roleBack)           out = [backend];
  else if (roleFull)           out = [backend, frontend];
  else if (titleTokens.length) out = titleTokens.slice(0, 2);
  else                         out = [backend, frontend];
  const seen = new Set(); const res = [];
  for (const t of out){ if (t && !seen.has(t)){ seen.add(t); res.push(t); } }
  return res.slice(0, 2);
}

const COMPARABLE_PAIRS = [
  ['Angular','React','Vue.js'],
  ['Angular','AngularJS'],
  ['Express','NestJS','Koa','Fastify'],
  ['Django','FastAPI','Flask'],
  ['Spring Boot','Quarkus','Micronaut'],
  ['PostgreSQL','MySQL','MariaDB','Oracle','SQL Server','SQL'],
  ['Hibernate','JPA','Spring Data'],
  ['SCSS','SASS','Less'],
  ['Jest','Mocha','Jasmine','Vitest'],
  ['Cypress','Playwright','Selenium','WebdriverIO']
];
const ALWAYS_COMPARABLE = new Set(['PostgreSQL','MySQL','MariaDB','Oracle','SQL Server','SQL','AngularJS'].map(norm));
const VERSION_LINEAGE = [['angular','angularjs']];
function isLineage(a, b){ return VERSION_LINEAGE.some(p => p.includes(a) && p.includes(b) && a !== b); }
function findComparable(reqTech, allowedNorm){
  const rn = norm(reqTech);
  if (!ALWAYS_COMPARABLE.has(rn) && !allowedNorm.includes(rn)) return null;
  for (const pair of COMPARABLE_PAIRS){
    const pl = pair.map(norm);
    if (!pl.includes(rn)) continue;
    for (let i=0;i<pair.length;i++){
      if (pl[i]===rn) continue;
      if (candidateSet.has(pl[i])){
        const idx = candidateNorm.indexOf(pl[i]);
        const cvTech = idx!==-1 ? candidateSkills[idx] : pair[i];
        if (isLineage(rn, pl[i])) return `${reqTech} (имаш познания от ${cvTech})`;
        return `${cvTech} (алтернатива на ${reqTech})`;
      }
    }
  }
  return null;
}

function levelRank(s){
  const t = ' ' + (s||'').toLowerCase() + ' ';
  if (t.includes('lead')||t.includes('principal')||t.includes('staff')||t.includes('chief')||t.includes('architect')||t.includes('head of')) return 4;
  if (t.includes('senior')||t.includes('sr.')||t.includes('sr ')) return 3;
  if (t.includes('middle')||t.includes('mid-')||t.includes('mid ')||t.includes('intermediate')||t.includes('regular')) return 2;
  if (t.includes('junior')||t.includes('jr.')||t.includes('jr ')||t.includes('entry')||t.includes('graduate')||t.includes('trainee')||t.includes('intern')) return 1;
  return 0;
}
// Candidate seniority = level implied by TOTAL years (bands: <2 Junior, 2-5 Mid, 5-10 Senior, 10+ Lead),
// falling back to the extractor's word if years are missing. Held titles may lift the level by AT MOST
// one step above what the years imply (and never lower it) — credits real seniority without letting an
// inflated title (e.g. "Senior" at 2 yrs) over-promote. If no title carries a seniority word, years win.
function bandRank(y){ if (y >= 10) return 4; if (y >= 5) return 3; if (y >= 2) return 2; return 1; }
const yearsRank = (cv.years_of_experience > 0) ? bandRank(cv.years_of_experience) : levelRank(cv.experience_level);
const titleRank = Math.max(0, ...(cv.job_titles || []).map(levelRank));
const candRank = titleRank > 0 ? Math.max(yearsRank, Math.min(titleRank, yearsRank + 1)) : yearsRank;
const SHOW_THRESHOLD = 30;

const scored = requirements.map((req, i) => {
  const allowedNorm = (req.accepts_alternatives_for || []).map(norm);
  const matched = [];
  const missing = [];

  function coverTech(t){
    const nt = norm(t);
    if (candidateSet.has(nt)) {
      if (LANGUAGES.has(nt) && primarySet.size > 0 && !primarySet.has(nt)) {
        const src = derivedFrom[nt];
        matched.push(src ? `${t} (имаш познания от ${src})` : `${t} (имаш познания)`);
        return SECONDARY_LANG_CREDIT;
      }
      matched.push(t);
      return 1;
    }
    const comp = findComparable(t, allowedNorm);
    if (comp) { matched.push(comp); return 0.5; }
    missing.push(t);
    return 0;
  }

  const prefTech = req.preferred_tech || [];
  const methods = req.methodologies || [];
  const langs = req.human_languages || [];

  const jobTags = String((jobs[i] || {}).description || '').replace('Tech stack:', '').split(',').map(s => s.trim()).filter(Boolean);
  const knownNorm = new Set([...(req.required_tech || []), ...prefTech].map(norm));
  const reqTech = [...(req.required_tech || [])];
  for (const tag of jobTags) {
    const tn = norm(tag);
    if (!tn || knownNorm.has(tn) || HUMAN_LANGS.has(tn)) continue;
    if ([...knownNorm].some(k => isLineage(tn, k))) continue;
    knownNorm.add(tn); reqTech.push(tag);
  }

  for (const alt of (req.accepts_alternatives_for || [])) {
    const an = norm(alt);
    if (an && !knownNorm.has(an) && candidateSet.has(an)) { knownNorm.add(an); reqTech.push(alt); }
  }

  let aCovW = 0, aTotW = 0, coreCovW = 0, coreTotW = 0;
  for (const t of reqTech){
    const w = techWeight(t);
    const c = coverTech(t);
    aCovW += c * w; aTotW += w;
    if (!FOUNDATIONAL.has(norm(t))) { coreTotW += w; coreCovW += c * w; }
  }
  const aScore = (aTotW ? aCovW/aTotW : 1) * 0.60;
  const coreCoverage = coreTotW ? coreCovW/coreTotW : 1;

  let bCov = 0; for (const t of prefTech) bCov += coverTech(t);
  const bScore = (prefTech.length ? bCov/prefTech.length : 1) * 0.10;

  const jobRank = Math.max(levelRank(req.experience_level), levelRank((jobs[i]||{}).title));
  const meetsLevel = (candRank===0 || jobRank===0 || candRank>=jobRank);
  const meetsYears = years >= (req.experience_years_min||0);
  const expMatch = meetsLevel && meetsYears;
  const expGrade = expMatch ? 1 : ((meetsLevel || meetsYears) ? 0.6 : 0.2);
  const expScore = expGrade * 0.20;

  let mlItems = 0, mlCov = 0;
  for (const m of methods){ mlItems++; if (candidateSet.has(norm(m))){ mlCov++; matched.push(m); } else missing.push(m); }
  for (const l of langs){ mlItems++; if (langCovered(l)){ mlCov++; matched.push(l); } else missing.push(l); }
  const mlScore = (mlItems ? mlCov/mlItems : 1) * 0.10;

  const mainStackNorm = detectMainStack((jobs[i] || {}).title, (jobs[i] || {}).description);
  const mainLangs = mainStackNorm.filter(m => MAIN_LANG_SET.has(m));
  const decisive = mainLangs.length ? mainLangs : mainStackNorm;
  function coverMain(m){
    if (candidateSet.has(m)){
      if (LANGUAGES.has(m) && primarySet.size > 0 && !primarySet.has(m)) return 'weak';
      return 'strong';
    }
    if (allowedNorm.includes(m)){
      if ([...primarySet].some(p => allowedNorm.includes(p))) return 'strong';
      if (allowedNorm.some(a => candidateSet.has(a))) return 'weak';
    }
    return 'none';
  }
  let mainFactor = 1;
  if (decisive.length){
    const covs = decisive.map(coverMain);
    mainFactor = covs.includes('strong') ? 1 : (covs.includes('weak') ? 0.85 : 0.55);
  }
  let main_alt = '';
  for (const m of decisive){
    if (!candidateSet.has(m) && allowedNorm.includes(m)){
      const p = [...primarySet].find(x => allowedNorm.includes(x));
      if (p){ const idx = candidateNorm.indexOf(p); const have = idx !== -1 ? candidateSkills[idx] : p; main_alt = `${have} (приема се вместо ${MAIN_DISPLAY[m] || m})`; break; }
    }
  }
  const main_stack = mainStackNorm.map(m => MAIN_DISPLAY[m] || m);

  const raw = (aScore + bScore + expScore + mlScore) * 100;
  const coreFactor = coreTotW === 0 ? 1 : Math.min(1, 0.3 + 1.4 * coreCoverage);
  let score = Math.round(raw * coreFactor * mainFactor);
  if (!expMatch) score = Math.max(0, score - 5);

  const overqualified = candRank>0 && jobRank>0 && (candRank - jobRank >= 2);
  const matchedFinal = dedupSkills(matched);
  const matchedBases = new Set(matchedFinal.map(skillBase));
  const missingFinal = dedupSkills(missing).filter(m => !matchedBases.has(skillBase(m)));
  return { job_index: i+1, score, matched_skills: matchedFinal, missing_skills: missingFinal, experience_match: expMatch, main_stack, main_alt, _overq: overqualified };
});

const toSummarize = scored.filter(s => s.score >= SHOW_THRESHOLD && !s._overq);
const summary_text = toSummarize.map(s => {
